INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00083', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「本研究認為，機構在處理自然災害或外部事故時，積極尋找藉口與防衛抗辯容易使公眾產生不信任 或不滿意的反應。不同於過去的研究成果，如實驗室環境下的資訊接收研究、對新聞報導的文本分析 研究，本研究發現，危機傳播管理者對傳播策略若持較為消極的立場，亦即坦承錯誤，才是帶來正向 結果的危機溝通策略。」 根據上文，下列選項何者最符合文意？', '["機構的危機溝通策略是否受到信任，與機構的滿意度有關", "當危機屬於天然災害，公眾較能接受防衛抗辯的溝通策略", "處理實驗室資訊、新聞報導方面的危機，宜有積極的立場", "坦承錯誤的危機溝通策略看似消極，但效果較其他策略好"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00084', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「『安靜離職』指員工仍認真履行職責，但只做符合最低限度要求的工作，不企圖多做或做得更好。會想安 靜離職，可能是員工想更優先選擇自己的生活，不再有『工作等於人生』的心態。這也可能和疫情有關： 根據調查，完全遠端或混合辦公的員工中，超過一半不太清楚他們在工作上被賦予什麼期望，因此對前途 感到徬徨，甚至想要辭職或降低工作投入程度。專家建議主管可以每週與團隊成員進行十五至三十分鐘 有意義的對話，從一對一面談中確認同事承擔那些工作、他們對工作量的感受，以及他們是否能在各項工 作當中取得平衡。即使是短暫的談話，對協助員工克服工作超載也很有幫助，可避免導致焦慮及倦怠。對 年輕員工而言，知道主管可接受的標準，而主管也能清楚地引導他們，這件事尤為重要。」 根據上文，下列選項對「安靜離職」的敘述何者正確？', '["希望公司辭退自己的一種消極手段", "可用來指稱故意擺爛的不認真員工", "個人主義使員工將個人生活的順位，放到工作之前", "不了解自己被主管的期望，是造成此一心態的原因"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00085', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '承上題，主管如何避免員工安靜離職，下列敘述何者正確？', '["個別談話的重點在為公司規劃未來的營運方針", "應該讓員工明白辛苦工作可以獲得相當的報酬", "了解員工的工作負荷量和期待以避免工作超載", "調整員工的上下班時間與生活習慣為其中關鍵"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00086', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列文句「」中的成語運用，正確的選項是：', '["他自小刻苦勵學，所以學問淵博，知識豐富，堪稱「腹笥甚窘」", "只有抱持「曲突徙薪」的態度，才能防患未然，避免失敗的結果", "為政者若凡事「瞻前顧後」多所忌憚，就難以興利除弊，造福人群", "這部電視劇成功的塑造人物形象，連配角都「栩栩如生」，令人難忘 原本仕途看好的官員，因捲入貪污案而「兔死狐悲」，最終只得黯然下臺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00087', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「荷蘭人治下的臺灣，原為天然鹿場，當時嘉南平原和南北丘陵地區鹿群奔逐的場面，我們今天已難 再想像。」 描述此一現象，下列選項中適當的詞語是：', '["滄海桑田", "物是人非", "物換星移", "鹿死誰手 江山之助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00088', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '下列新聞內容的敘述，那些有語病？', '["儘管無緣晉級，在羽球分組預賽最後一戰，中華隊選手仍全力出擊，擊敗澳洲隊", "十大好人好事名單今日揭曉，來自臺北市的陳同學，因熱心協助同班的身障同學而獲獎", "都市更新與否影響各地店面租金：A地的店租是一坪五千元，B地則便宜五倍，每坪只要一千元", "本次亞洲都市評比競爭激烈，最終選出的前二十名裡，花蓮市以最高積分榮獲最美麗的都市之一 瑞典高等教育部長艾達．哈吉阿利奇宣布為日前酒駕傷人事件下台負責，他將面臨六個月的刑期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00089', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「臺灣的芒果品種都是外來種，包含經過馴化被俗稱『土芒果』的柴檨仔。1950年代愛文、凱特、海 頓這批『洋芒果』從美國引進，但不耐海島型溼熱氣候，品種面臨炭疽病的威脅，也嚴重影響賣相。 臺灣人拿日治時期由日本人從印度引進的『懷特』當母本，結合來自美國的『凱特』作父本，催生出 臺灣第一個自行育種成功的品種，命名為『金煌』。」 根據上文，下列選項符合文意的是：', '["柴檨仔與海頓屬於外國品種", "凱特芒果習慣美洲溼熱氣候", "混血金煌是為了防止炭疽病", "臺灣水土適合種植各國水果 馴化可改變水果的適應能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00090', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '麥帥為子祈禱文：「請陶冶我的兒子，使他的心地純潔，目標高超；在企圖駕馭他人之前，先能駕馭 自己；對未來善加籌劃，但是永不忘記過去。在他把以上諸點都已做到之後，還要賜給他充分的幽默 感，使他可以永遠保持嚴肅的態度，但絕不自視非凡，過於拘執。請賜給他謙遜，使他可以永遠記住 真實偉大的樸實無華，真實智慧的虛懷若谷，和真實力量的溫和蘊藉。」 根據上文，下列選項符合祈禱者觀點的是：', '["心地純潔者，才能大展鴻圖", "凡是成功者，必能駕馭他人", "汲取經驗，有助於規劃未來", "真正的智者，通常虛懷若谷 謙沖質樸，能成就更大事業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00091', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「『設計×臺北』海報設計目的，在於喚起臺灣對於城市與設計的議題與反思。畫面中心呈現出某政治 人物肖像，原因是城市規劃主要取決於意識形態，取決於政治家們；然而，此肖像的組成則是臺灣報 紙中的分類廣告欄，那些密密麻麻、五顏六色、奇奇怪怪，但卻活力四射、爭先恐後、呼之欲出的內 容，就如城市的新鮮細胞般，令人感受到亞洲大都會的活力與喧鬧。」 根據上文，下列選項敘述正確的是：', '["臺北是一座活力四射的亞洲大都會", "早期臺北城市樣貌是政治人物設計", "城市規劃與政治家的意識形態無關", "海報設計目的在於喚起人們的反思 藉由分類廣告可以感受城市的活力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00092', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '有三人進行一場桌上遊戲，玩家A在第60格、玩家B在第62格、玩家C在第43格。根據以下遊戲 規則的說明，推論正確的選項是： 甲、玩家輪流投擲點數分別為1～6的六面骰，根據所骰出的點數前進相對應的格子數 乙、如果玩家到了有鵝的紅色格子（第9／18／27／37／45／54格），必須倒退與骰子點數相同的步數 丙、當你剛好走到有其他玩家的格子，可以讓對方退回你上一輪所在的格子 丁、必須剛好抵達第63格才算獲勝，若超過第63格則必須倒退超出的步數', '["玩家A骰出2時會退回第58格", "玩家A骰出6時會停留在原處", "玩家B在這一回合就結束遊戲的機率比玩家A來得高", "玩家C這一輪結束後仍停留在第43格，可知他骰出了2點 玩家C骰完輪回玩家A的當下，遊戲盤上不會有玩家的棋子停留在有鵝的紅色格子上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
